mapper.select:
SELECT id, repair_item, vehicle_id, repair_person, location, repair_time, fee, condition_desc, material_desc, sender, remark, create_time, update_time FROM vehicle_repair
AND id = #{id}
AND vehicle_id = #{vehicleId}
AND repair_item LIKE CONCAT('%', #{repairItem}, '%')
AND repair_person LIKE CONCAT('%', #{repairPerson}, '%')
ORDER BY repair_time DESC

