repair_item = #{repairItem}, vehicle_id = #{vehicleId}, repair_person = #{repairPerson}, location = #{location}, repair_time = #{repairTime}, fee = #{fee}, condition_desc = #{conditionDesc}, material_desc = #{materialDesc}, sender = #{sender}, remark = #{remark}, update_time = #{updateTime}
